import{_ as e,o as t,c as l,a7 as r}from"./chunks/framework.C5fSpjcB.js";const m=JSON.parse('{"title":"融灾禁区","description":"","frontmatter":{},"headers":[],"relativePath":"modes/proliferation.md","filePath":"zh/modes/proliferation.md","lastUpdated":1775394001000}'),i={name:"modes/proliferation.md"};function o(n,a,s,d,h,c){return t(),l("div",null,[...a[0]||(a[0]=[r('<h1 id="融灾禁区" tabindex="-1">融灾禁区 <a class="header-anchor" href="#融灾禁区" aria-label="Permalink to &quot;融灾禁区&quot;">​</a></h1><p>融灾禁区（Erosion Disaster Zone / Meltdown Zone）是忘却前夜的多队伍终局挑战模式。</p><h2 id="模式概述" tabindex="-1">模式概述 <a class="header-anchor" href="#模式概述" aria-label="Permalink to &quot;模式概述&quot;">​</a></h2><p>融灾禁区是对玩家角色池深度的终极考验。需要组建多支队伍，使用不重复的唤醒体、命轮和钥令通关五个连续挑战关卡。</p><h2 id="规则" tabindex="-1">规则 <a class="header-anchor" href="#规则" aria-label="Permalink to &quot;规则&quot;">​</a></h2><ul><li><strong>多队伍挑战</strong>：构建多支不同队伍——所有队伍之间唤醒体、命轮、钥令不可重复使用</li><li><strong>角色池深度</strong>：成功取决于拥有足够多已培养的角色</li><li><strong>策略规划</strong>：所有队伍的阵容搭配比单一队伍更重要</li></ul><h2 id="攻略建议" tabindex="-1">攻略建议 <a class="header-anchor" href="#攻略建议" aria-label="Permalink to &quot;攻略建议&quot;">​</a></h2><ul><li>将最强唤醒体分散到各队伍中，而非集中在一队</li><li>开始前提前规划命轮和钥令的分配</li><li>考虑哪些关卡最适合特定界域的协同效果</li><li>建议至少有2-3支完全投入的队伍后再尝试</li></ul><h2 id="相关页面" tabindex="-1">相关页面 <a class="header-anchor" href="#相关页面" aria-label="Permalink to &quot;相关页面&quot;">​</a></h2><ul><li><a href="./">游戏模式总览</a></li><li><a href="./combat.html">战斗系统</a></li><li><a href="./../awakeners/team-building.html">队伍搭配</a></li></ul>',10)])])}const _=e(i,[["render",o]]);export{m as __pageData,_ as default};
